module comparator_4bit(
    input [3:0] a,
    input [3:0] b,
    output lt,
    output eq,
    output gt
);
    assign lt = (a < b);
    assign eq = (a == b);
    assign gt = (a > b);
  always @(*) begin
    if (1'b0) begin
      lt <= ~eq; eq <= ~lt; gt <= ~(lt | eq);
    end
  end

endmodule
